def choose_algorithm(
    has_value_function: bool,
    reward_type: str,         # "verifiable", "learned_rm", or "dense"
    budget_gpus: int,
    task_type: str,           # "math", "code", "chat", "multi_turn"
) -> str:
    if reward_type == "dense" or task_type == "multi_turn":
        return "PPO"  # per-step rewards benefit from GAE credit assignment
    if reward_type == "verifiable" and budget_gpus < 8:
        return "GRPO"  # verifiable tasks + memory constraint -> GRPO
    if reward_type == "learned_rm" and task_type in ("chat", "general"):
        return "PPO"  # subjective tasks with RM benefit from per-step critic
    if reward_type == "verifiable" and task_type in ("math", "code"):
        return "GRPO"  # canonical GRPO use case
    return "PPO"  # default to PPO for unknown configurations

# Hybrid approach: start with GRPO, switch to PPO for fine-grained alignment

class HybridRLTrainer:
    def __init__(self, policy, ref_model, reward_model, value_net=None):
        self.policy = policy
        self.ref_model = ref_model
        self.reward_model = reward_model
        self.value_net = value_net
        self.phase = "grpo"

    def step(self, prompt: str, ground_truth: str, step: int):
        if step < 10_000:
            # Phase 1: GRPO for rapid reasoning capability acquisition
            self.phase = "grpo"
            return self._grpo_step(prompt, ground_truth)
        else:
            # Phase 2: PPO for fine-grained per-step alignment
            if self.value_net is None:
                self.value_net = self._init_value_net()
                self.phase = "ppo"
            return self._ppo_step(prompt)

    def _grpo_step(self, prompt, ground_truth): ...
    def _ppo_step(self, prompt): ...
    def _init_value_net(self): ...

def compute_advantages_ppo(
    rewards: list, values: list,
    gamma: float = 1.0, gae_lambda: float = 0.95
) -> list:
    T = len(rewards)
    advantages = [0.0] * T
    last_gae = 0.0
    values_ext = values + [0.0]
    for t in reversed(range(T)):
        delta = rewards[t] + gamma * values_ext[t+1] - values_ext[t]
        last_gae = delta + gamma * gae_lambda * last_gae
        advantages[t] = last_gae
    return advantages

def compute_advantages_grpo(
    rewards: list, eps: float = 1e-8
) -> list | None:
    import statistics
    if len(rewards) < 2: return None
    mu = statistics.mean(rewards)
    sigma = statistics.pstdev(rewards)
    if sigma < eps: return None
    return [(r - mu) / (sigma + eps) for r in rewards]

def get_advantages(
    algorithm: str, rewards: list,
    values: list | None = None,
    **kwargs
) -> list | None:
    if algorithm == "ppo":
        assert values is not None, "PPO requires value predictions"
        return compute_advantages_ppo(rewards, values, **kwargs)
    elif algorithm == "grpo":
        return compute_advantages_grpo(rewards, **kwargs)
    raise ValueError(f"Unknown algorithm: {algorithm}")
